import{_ as l,o as a,c as o,ai as i}from"./chunks/framework.CaiDwmc7.js";const c=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"01 Геймдизайн/Реализация иммерсивности.md","filePath":"01 Геймдизайн/Реализация иммерсивности.md"}'),t={name:"01 Геймдизайн/Реализация иммерсивности.md"};function n(e,r,s,g,h,_){return a(),o("div",null,[...r[0]||(r[0]=[i('<h3 id="геимплеиные-механики" tabindex="-1">Геймплейные механики <a class="header-anchor" href="#геимплеиные-механики" aria-label="Permalink to “Геймплейные механики”">​</a></h3><h5 id="работа-с-ульем" tabindex="-1">Работа с ульем <a class="header-anchor" href="#работа-с-ульем" aria-label="Permalink to “Работа с ульем”">​</a></h5><ol><li><strong>Осмотр рамок.</strong> Игрок подходит у клью, снимает крышку, у крышки есть вес. Достает подкрышник, снимает пленку, видит установленные рамки. С помощью стамески вытаскивает рамки. На рамке видны соты, расплод, перга, запечатанный и открытый мед. Можно реализовать зум на рамку, чтобы игрок мог внимательно рассмотреть состояние. Обратный процесс при закрытии улья: вставить рамки, накрыть пленкой, затем подкрышником и крышкой.</li><li><strong>Дым и инструменты.</strong> Использование дымаря для успокоения пчел должно быть обязательным, однако у игрока должна быть возможность открыть улей без него, чтобы узнать, как ведут себя агрессивные пчелы. Игрок должен предварительно взять инвентарь (дымарь, стамеску, щеточку для сметания пчел и сетку на лицо) в мастерской.</li><li><strong>Обнаружение проблем.</strong> На рамках можно найти признаки болезней или вредителей. Игрок должен уметь идентифицировать проблему и принимать меры (лечение, удаление пораженных участков).</li><li><strong>Роение.</strong> <em>(Не входит в вертикльный срез)</em> Если игрок пропустил момент и улей переполнен, может произойти роение - пчелы вылетят из улья, соберутся в рой и улетят. Игрок увидит рой пчел на ветке дерева рядом с ульем, должен его аккуратно снять и переселить в новый улей.</li></ol><h5 id="циклы-и-сезонность" tabindex="-1">Циклы и сезонность <a class="header-anchor" href="#циклы-и-сезонность" aria-label="Permalink to “Циклы и сезонность”">​</a></h5><ol><li><strong>Весна</strong> Осмотр ульев после зимовки, чистка ульев от старых рамок, установка новых рамок для наполнения, подкормка, расширение семей, починка ульев при необходимости.</li><li><strong>Лето</strong> Главный медосбор. Нужно вовремя ставить магазинные надставки (дополнительные корпуса улья для сбора меда), откачивать мед. В жаркую погоду пчелы вентилируют улей, нужно следить за вентиляцией.</li><li><strong>Осень</strong> <em>Можно не включать в вертикальный срез</em> Подготовка к зиме: сокращение гнезд, сборка ульев, обработка от варроатоза, подкормка сахарным сиропом</li><li><strong>Зима</strong> <em>Можно не включать в вертикальный срез</em> Минимум активности. Игрок может утеплять улья, проверять наличие корма (не открывая улей, а оценивая вес или слушая звук), предотвращать попадание внутрь ульев мышей и других животных.</li><li><strong>Суточный цикл</strong> Поведение пчел меняется в зависимости от времени суток. Днем пчелы наиболее активны и вылетают из улья, к вечеру становятся более агрессивными, ночью улей отдыхает.</li></ol><h5 id="биология-и-поведение-пчел" tabindex="-1">Биология и поведение пчел <a class="header-anchor" href="#биология-и-поведение-пчел" aria-label="Permalink to “Биология и поведение пчел”">​</a></h5><ol><li><strong>Распределение ролей</strong> В улье есть матка, трутни и различные рабочие пчелы, у каждой свой функция, при дисбалансе в распределении ролей улей страдает целиком.</li><li><strong>Танцы пчел</strong> <em>(не входит в вертикальный срез)</em> Пчелы общаются с помощью сигналов, которые игрок может научиться опознавать и использовать в своей работе.</li><li><strong>Влияние погоды</strong> Пчелы не летают в додь, сильный ветер и холод, игрок должен учитывать прогноз погоды для своего геймплея и предотвращать несчастные случаи на пасеке</li><li><strong>Здоровье</strong> Обязательная симуляция клеща варроа - главного врага пчел. В дальнейшей игре после вертикального среза стоит симулировать все распространенные болезни и паразитов.</li><li><strong>Укусы</strong> Укусы пчел причиняют боль (визуальный эффект + звук + индикатор до применения лекарства), их нужно лечить.</li></ol><h3 id="физика-и-взаимодеиствие-с-миром" tabindex="-1">Физика и взаимодействие с миром <a class="header-anchor" href="#физика-и-взаимодеиствие-с-миром" aria-label="Permalink to “Физика и взаимодействие с миром”">​</a></h3><ol><li><strong>Физика предметов</strong> Ящики ульев и все их части должны иметь вес. Перемещать улей тяжело, он не телепортируется. Рамки с медом тяжелые, игрок несет их аккуратно, чтобы не уронить.</li><li><strong>Вязкость жидкостей</strong> Мед густой. При переливани и откачке он должен медленно и красиво стекать, создавая медовые нити. При разливе он остается лужицей.</li><li><strong>Разрушаемость и износ</strong> <em>Можно не включать в вертикальный срез</em> Инструменты со временем изнашиваются, как и ульи.</li></ol><h3 id="визуальныи-и-звуковои-дизаин" tabindex="-1">Визуальный и звуковой дизайн <a class="header-anchor" href="#визуальныи-и-звуковои-дизаин" aria-label="Permalink to “Визуальный и звуковой дизайн”">​</a></h3><h4 id="звук" tabindex="-1">Звук <a class="header-anchor" href="#звук" aria-label="Permalink to “Звук”">​</a></h4><ol><li><strong>Гул улья</strong> Звук должен меняться в зависимости от состояния. Спокойный гул - все хорошо. Громкий, тревожный гул - пчелы агрессивны. Тихий, слабый гул - семья голодает или больна.</li><li><strong>Звуки внутри улья</strong> При приближении к рамке звуки более детальные: жужжание, хруст воска, возня</li><li><strong>Природа</strong> Пение птиц, шелест листвы, звуки дождя, отдаленный гром, ветер, звуки шагов игрока.</li><li><strong>Инструменты</strong> Шипение дымаря, скрежет стамески, звон стеклянной банки</li></ol><h4 id="графика-и-детализация" tabindex="-1">Графика и детализация <a class="header-anchor" href="#графика-и-детализация" aria-label="Permalink to “Графика и детализация”">​</a></h4><ol><li><strong>Камера</strong> Вид от первого лица. Игрок должен видеть свои руки в перчатках, держащие рамку и другие инструменты. При надевании головных уборов и защитных костюмов меняется обзор</li><li><strong>Детализация объектов</strong> Пчелы должны быть проработаны: пушистые тельца, крылышки. Соты должны выглядеть как восковые шестиугольники с переливами меда на свету. Пыльца на задних лапках фуражиров - яркие шарики.</li><li><strong>Смена дня и ночи, погода</strong> Разные состояния окружающего мира</li></ol><h3 id="интерфеис-и-ux" tabindex="-1">Интерфейс и UX <a class="header-anchor" href="#интерфеис-и-ux" aria-label="Permalink to “Интерфейс и UX”">​</a></h3><ol><li><strong>Инвентарь</strong> Не меню на паузе, а физический инвентарь в мастерской, с собой игрок носит ограниченное количество инструментов.</li><li><strong>Подсказки</strong> Обучение вплетается в геймплей и обусловлено нарративом. Визуальные подсказки при действиях ненавязчивые и минимальные.</li></ol><h3 id="открытыи-мир-и-экосистема" tabindex="-1">Открытый мир и экосистема <a class="header-anchor" href="#открытыи-мир-и-экосистема" aria-label="Permalink to “Открытый мир и экосистема”">​</a></h3><ol><li><strong>Карта и медоносы</strong> Разные растения цветут в разное время, мед с разных растений также различается. Игрок должен знать, где находятся поля гречихи, липовые рощи, луга с разнотравьем. Игрок также может самостоятельно сеять медоносы и ухаживать за ними, чтобы улучшить медосбор.</li><li><strong>Животные и угрозы</strong> Птицы, вредители, грызуны, а также хищники могут представлять опасность. Кроме того, фермеры могут обрабатывать поля пестицидами, что также повлияет на здоровье пчел.</li></ol><h3 id="прогрессия-и-цели" tabindex="-1">Прогрессия и цели <a class="header-anchor" href="#прогрессия-и-цели" aria-label="Permalink to “Прогрессия и цели”">​</a></h3><ol><li><strong>Развитие пасеки</strong> Возможность расширяться: от 2-3 ульев до промышленной пасеки. Есть возможность покупки более совершенного оборудования, дополнительных участков земли, улучшения мастерской.</li><li><strong>Экономика</strong> Продажа меда разных сортов, воска и продуктов из него, прополиса, пыльцы, маточного молочка, отводков пчел. Цены колеблются в зависимости от спроса.</li><li><strong>Исследования</strong> Ведение дневника пасечника, куда автоматически записываются наблюдения (погода, взяток, болезни), чтобы становиться более опытным пчеловодом.</li><li><strong>Достижения</strong> Завести редку породу пчел с особыми характеристиками и другие ачивки, которые может получать игрок. Достижения функциональны и дают бонусы игроку, что мотивирует его развиваться.</li></ol>',20)])])}const m=l(t,[["render",n]]);export{c as __pageData,m as default};
